REST = [
    # 9 cloud84 — Yom Kippur Kohen Gadol ketoret
    (
        "\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05d4\u05e2\u05d1\u05d5\u05d3\u05d4 \u05d4\u05e7\u05e9\u05d4 \u05d1\u05d9\u05d5\u05ea\u05e8 \u05e9\u05d1\u05d5\u05e6\u05e2\u05d4 \u05d1\u05de\u05e7\u05d3\u05e9! \u05d9\u05d5\u05dd \u05db\u05d9\u05e4\u05d5\u05e8 \u05d4\u05d9\u05d4 \u05d4\u05d9\u05d5\u05dd \u05d4\u05d9\u05d7\u05d9\u05d3\u05d9 \u05d1\u05e9\u05e0\u05d4 \u05e9\u05d1\u05d5 \u05d0\u05d3\u05dd \u05d9\u05db\u05d5\u05dc \u05d4\u05d9\u05d4 \u05dc\u05d4\u05d9\u05db\u05e0\u05e1 \u05dc\u05e7\u05d5\u05d3\u05e9 \u05d4\u05e7\u05d3\u05e9\u05d9\u05dd \u2014 \u05d4\u05d7\u05d3\u05e8 \u05d4\u05e7\u05d3\u05d5\u05e9 \u05d1\u05d9\u05d5\u05ea\u05e8 \u05d1\u05d0\u05d3\u05de\u05d4 \u2014 \u05d5\u05d4\u05db\u05dc \u05ea\u05dc\u05d4 \u05d1\u05d0\u05d3\u05dd \u05d0\u05d7\u05d3: \u05d4\u05db\u05d4\u05df \u05d4\u05d2\u05d3\u05d5\u05dc. "
        "\u05d0\u05dd \u05dc\u05d0 \u05d4\u05d9\u05d4 \u05db\u05d3\u05d0\u05d9, \u05e1\u05d1\u05d9\u05e8 \u05dc\u05d4\u05d9\u05d5\u05ea \u05e9\u05d9\u05de\u05d5\u05ea \u05d1\u05de\u05e2\u05e9\u05d4 \u2014 \u05d0\u05d6 \u05d4\u05dc\u05d7\u05e5 \u05d4\u05d9\u05ea\u05d4 \u05e2\u05e6\u05d5\u05de\u05d4! \u05d4\u05de\u05d8\u05e8\u05d4: \u05dc\u05d4\u05e7\u05e8\u05d9\u05d1 \u05e7\u05d8\u05d5\u05e8\u05ea \u05e9\u05ea\u05de\u05dc\u05d0 \u05d0\u05ea \u05e7\u05d5\u05d3\u05e9 \u05d4\u05e7\u05d3\u05e9\u05d9\u05dd \u05d1\u05e2\u05e0\u05df \u05e2\u05d1\u05d4 \u05d5\u05e7\u05d3\u05d5\u05e9\u05d4 \u05d1\u05de\u05d9\u05d5\u05d7\u05d3. "
        "\u05dc\u05e7\u05d5\u05e8\u05d1\u05df \u05d6\u05d4 \u05d4\u05db\u05d4\u05df \u05d4\u05d2\u05d3\u05d5\u05dc \u05d4\u05e9\u05ea\u05de\u05e9 \u05d1\u05d9\u05d3\u05d9\u05d5 \u05db\u05de\u05d3\u05d4. \u05d8\u05d1\u05dc \u05d0\u05e6\u05d1\u05e2\u05d5 \u05dc\u05ea\u05d5\u05da \u05db\u05dc\u05d9 \u05d2\u05d3\u05d5\u05dc \u05e9\u05dc \u05e7\u05d8\u05d5\u05e8\u05ea \u05d8\u05d7\u05d5\u05df \u05d8\u05d7\u05d5\u05df \u05d5\u05dc\u05d9\u05e7\u05d8 \u05d1\u05d3\u05d9\u05d5\u05e7 \u05d0\u05ea \u05de\u05d4 \u05e9\u05db\u05e4\u05d5\u05ea \u05d9\u05d3\u05d9\u05d5 \u05d9\u05db\u05d5\u05dc\u05d5\u05ea \u05dc\u05d4\u05db\u05d9\u05dc \u2014 \u05dc\u05d0 \u05d9\u05d5\u05ea\u05e8 \u05d5\u05dc\u05d0 \u05e4\u05d7\u05d5\u05ea. "
        "\u05d4\u05e0\u05d9\u05d7 \u05d0\u05ea \u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05dc\u05db\u05e4\u05d9 \u05d6\u05d4\u05d1, \u05dc\u05e7\u05d7 \u05de\u05d7\u05ea\u05d4 \u05de\u05dc\u05d0\u05d4 \u05d2\u05d7\u05de\u05d9\u05dd \u05d1\u05d5\u05e2\u05e8\u05d5\u05ea, \u05d5\u05e0\u05db\u05e0\u05e1 \u05dc\u05e7\u05d5\u05d3\u05e9 \u05d4\u05e7\u05d3\u05e9\u05d9\u05dd. \u05d4\u05d9\u05d4 \u05e6\u05e8\u05d9\u05da \u05dc\u05e9\u05de\u05d5\u05e8 \u05e2\u05dc \u05d4\u05e2\u05e8\u05de\u05d4 \u05d4\u05de\u05d3\u05d5\u05d9\u05e7\u05ea \u05de\u05d1\u05dc \u05dc\u05d4\u05e4\u05d9\u05dc \u05d0\u05e4\u05d9\u05dc \u05d2\u05e8\u05d2\u05d9\u05e8 \u05d1\u05d6\u05de\u05df \u05d4\u05d4\u05dc\u05d9\u05db\u05d4. "
        "\u05d1\u05ea\u05d5\u05da, \u05d4\u05e0\u05d9\u05d7 \u05d0\u05ea \u05d4\u05d2\u05d7\u05de\u05d9\u05dd \u05e2\u05dc \u05d4\u05d2\u05d7\u05dc\u05d9\u05dd \u2014 \u05d1\u05e6\u05d3 \u05d4\u05de\u05e8\u05d5\u05e7 \u05d4\u05e8\u05d7\u05d5\u05e7 \u05de\u05de\u05e7\u05d5\u05dd \u05e2\u05de\u05d3\u05d5 \u2014 \u05db\u05d3\u05d9 \u05dc\u05d0 \u05dc\u05d9\u05d1\u05e2\u05e8 \u05db\u05e9\u05d4\u05d0\u05e9 \u05ea\u05ea\u05e2\u05dc\u05d4. \u05db\u05d0\u05df \u05d4\u05e7\u05e9\u05d4 \u05e2\u05dc\u05ea\u05d4 \u05e8\u05de\u05d4: \u05d4\u05d9\u05d4 \u05e6\u05e8\u05d9\u05da \u05dc\u05d4\u05e2\u05d1\u05d9\u05e8 \u05d0\u05ea \u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05de\u05d4\u05db\u05e4\u05d9 \u05dc\u05e9\u05ea\u05d9 \u05d9\u05d3\u05d9\u05d5 \u05d1\u05dc\u05d1\u05d3 \u05d1\u05dc\u05d9 \u05db\u05dc\u05d9! "
        "\u05d7\u05d9\u05d9\u05d1 \u05d4\u05d9\u05d4 \u05dc\u05d0\u05d6\u05df \u05d0\u05ea \u05d4\u05db\u05e4\u05d9 \u05e2\u05d3 \u05e9\u05d4\u05d5\u05d0 \u05de\u05d0\u05d5\u05d6\u05df \u05d5\u05e8\u05d5\u05e2\u05d3 \u05d0\u05ea \u05d4\u05ea\u05d5\u05db\u05df \u05dc\u05db\u05e4\u05d5\u05ea \u05d4\u05d9\u05d3\u05d9\u05d9\u05dd \u05d4\u05e4\u05ea\u05d5\u05d7\u05d5\u05ea. \u05d6\u05d5 \u05d4\u05e2\u05d1\u05d5\u05d3\u05d4 \u05d4\u05e7\u05e9\u05d4 \u05d1\u05d9\u05d5\u05ea\u05e8 \u05e9\u05d1\u05d5\u05e6\u05e2\u05d4 \u05d1\u05de\u05e7\u05d3\u05e9. "
        "\u05db\u05e9\u05d9\u05e6\u05d0 \u05de\u05e7\u05d5\u05d3\u05e9 \u05d4\u05e7\u05d3\u05e9\u05d9\u05dd, \u05d4\u05e7\u05d4\u05dc \u05dc\u05d9\u05d5\u05d5 \u05d0\u05d5\u05ea\u05d5 \u05d1\u05e9\u05de\u05d7\u05d4 \u05dc\u05d1\u05d9\u05ea\u05d5, \u05d5\u05d4\u05d5\u05d0 \u05e2\u05e8\u05da \u05e1\u05e2\u05d5\u05d3 \u05d0\u05d7\u05e8\u05d9 \u05d4\u05e6\u05d5\u05dd \U0001f389. \u05de\u05d3\u05d1\u05e8\u05d9\u05dd \u05e2\u05dc \u05d9\u05d5\u05dd \u05e7\u05e9\u05d4 \u05d1\u05de\u05e7\u05d3\u05e9!"
    ),
    # 10 cloud85 — Parah Adumah
    (
        "\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05e4\u05e8\u05d4 \u05d0\u05d3\u05d5\u05de\u05d4 \u2014 \u05d0\u05d7\u05ea \u05d4\u05d7\u05d5\u05e7\u05d9\u05dd \u05d4\u05de\u05d1\u05d9\u05d0\u05d9\u05dd \u05d1\u05d9\u05d5\u05ea\u05e8 \u05d1\u05ea\u05d5\u05e8\u05d4! \U0001f404 "
        "\u05e4\u05e8\u05d4 \u05d0\u05d3\u05d5\u05de\u05d4 \u05d4\u05d9\u05ea\u05d4 \u05e0\u05d7\u05d5\u05e6\u05d4 \u05dc\u05d8\u05d4\u05e8 \u05de\u05d8\u05d5\u05de\u05d0 \u05de\u05d2\u05e2 \u05d1\u05de\u05ea, \u05d5\u05d4\u05d9\u05d0 \u05d4\u05d9\u05ea\u05d4 \u05d7\u05d9\u05d5\u05e0\u05d9\u05ea \u05dc\u05e2\u05d1\u05d5\u05d3\u05d4 \u05d1\u05de\u05e7\u05d3\u05e9. "
        "\u05de\u05d9 \u05e9\u05dc\u05d0 \u05d8\u05d4\u05e8 \u05d5\u05e0\u05db\u05e0\u05e1 \u05dc\u05de\u05e7\u05d3\u05e9 \u05d1\u05dc\u05d9 \u05d8\u05d4\u05d9\u05dc\u05d4 \u2014 \u05d7\u05d9\u05d9\u05d1 \u05d1\u05db\u05d5\u05ea\u05e8 \u05d1\u05e7\u05d9\u05d5\u05e8\u05d1\u05df. "
        "\u05d4\u05e4\u05e8\u05d3\u05d5\u05e7\u05e1 \u05e9\u05d1\u05d9\u05d1\u05d9\u05df \u05d0\u05e4\u05d9\u05dc\u05d5 \u05e9\u05dc\u05de\u05d4 \u05d4\u05de\u05dc\u05da: \u05e4\u05e8\u05d4 \u05d0\u05d3\u05d5\u05de\u05d4 \u05dc\u05d7\u05dc\u05d5\u05d8 \u05e0\u05e1\u05e2\u05ea \u05e2\u05dd \u05e2\u05e6\u05d9 \u05d0\u05e8\u05d6, \u05d0\u05d6\u05d5\u05d1 \u05d5\u05e9\u05e0\u05d9 \u05ea\u05d5\u05dc\u05e2\u05ea \u05e9\u05e0\u05d9 \u2014 \u05d5\u05e9\u05e0\u05d9 \u05e9\u05e2\u05e8\u05d5\u05ea \u05e9\u05d0\u05d9\u05e0\u05df \u05d0\u05d3\u05d5\u05de\u05d9\u05dd \u05de\u05e4\u05e1\u05dc\u05d5\u05ea \u05d0\u05d5\u05ea\u05d4! "
        "\u05d4\u05d0\u05e4\u05e8 \u05de\u05e2\u05d5\u05e8\u05d1\u05d1\u05d9\u05dd \u05d1\u05de\u05d9\u05dd \u05d5\u05d6\u05d5\u05e8\u05e7\u05d9\u05dd \u05e2\u05dc \u05de\u05d9 \u05e9\u05d8\u05d9\u05de\u05ea \u05de\u05d8\u05d5\u05de\u05d0 \u05d5\u05d4\u05d5\u05d0 \u05d4\u05d5\u05e4\u05da \u05d8\u05d4\u05d5\u05e8. \u05d4\u05de\u05d6\u05e8\u05d9\u05e7? \u05d4\u05d5\u05e4\u05da \u05d8\u05de\u05d0. \u05d6\u05d4 \u05d4\u05d3\u05d5\u05d2\u05de\u05d4 \u05d4\u05de\u05e8\u05db\u05d6\u05d9\u05ea \u05dc\u05d7\u05d5\u05e7 \u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05e2\u05d5\u05e9\u05d9\u05dd \u05de\u05d8\u05e2\u05dd \u05e1\u05de\u05db\u05d5\u05ea \u05d0\u05dc\u05d5\u05e7\u05d9\u05ea, \u05dc\u05d0 \u05de\u05d8\u05e2\u05dd \u05d0\u05e0\u05d5\u05e9\u05d9. \u05dc\u05de\u05d3\u05d5 \u05e2\u05d5\u05d3!"
    ),
    # 11 cloud86 — tumat meit
    (
        "\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05d8\u05d5\u05de\u05d0\u05ea \u05de\u05d9\u05ea \u2014 \u05d8\u05d5\u05de\u05d0\u05d4 \u05de\u05d2\u05e2 \u05d1\u05de\u05ea \u2014 \u05d5\u05e2\u05dc \u05db\u05d9 \u05d6\u05d5 \u05d4\u05d8\u05d5\u05de\u05d0\u05d4 \u05d4\u05d7\u05d6\u05e7\u05d4 \u05d1\u05d9\u05d5\u05ea\u05e8 \u05d1\u05db\u05dc \u05d4\u05dc\u05db\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea! \u2620\ufe0f "
        "\u05de\u05ea \u05e0\u05e7\u05e8\u05d0 \u05d0\u05d1 \u05d0\u05d1\u05d5\u05ea \u05d4\u05d8\u05d5\u05de\u05d0\u05d5\u05ea \u2014 \u05d4\u05e8\u05de\u05d4 \u05d4\u05d2\u05d1\u05d5\u05d4\u05d4 \u05d1\u05d9\u05d5\u05ea\u05e8 \u05d1\u05de\u05e2\u05e8\u05db\u05ea \u05d4\u05d8\u05d5\u05de\u05d0\u05d5\u05ea \u05e9\u05dc \u05d4\u05ea\u05d5\u05e8\u05d4. "
        "(1) \u05de\u05d2\u05e2 \u05d9\u05e9\u05d9\u05e8 \u2014 \u05e0\u05d5\u05d2\u05e2 \u05d1\u05de\u05ea \u05de\u05d8\u05de\u05d0 \u05e9\u05d1\u05e2\u05d4 \u05d9\u05de\u05d9\u05dd. (2) \u05e0\u05e9\u05d9\u05d0\u05ea \u05de\u05ea \u2014 \u05d2\u05dd \u05dc\u05dc\u05d0 \u05de\u05d2\u05e2 \u05de\u05d8\u05de\u05d0 \u05e9\u05d1\u05e2\u05d4 \u05d9\u05de\u05d9\u05dd. "
        "(3) \u05d8\u05d5\u05de\u05d0\u05ea \u05d0\u05d5\u05d4\u05dc \u2014 \u05db\u05dc \u05de\u05d9 \u05d0\u05d5 \u05db\u05dc \u05d3\u05d1\u05e8 \u05d1\u05d0\u05d5\u05d4\u05dc \u05e2\u05dd \u05de\u05ea \u05de\u05d8\u05de\u05d0, \u05d2\u05dd \u05dc\u05dc\u05d0 \u05de\u05d2\u05e2! "
        "\u05dc\u05db\u05df \u05dc\u05db\u05d4\u05e0\u05d9\u05dd \u05d0\u05e1\u05d5\u05e8 \u05dc\u05d4\u05d9\u05db\u05e0\u05e1 \u05dc\u05d1\u05d9\u05ea \u05e2\u05dd \u05de\u05ea \u05d0\u05d5 \u05dc\u05d4\u05dc\u05da \u05e2\u05dc \u05e7\u05d1\u05e8. \u05d4\u05d8\u05d4\u05e8\u05d4: \u05de\u05d9 \u05e9\u05d8\u05d9\u05de\u05ea \u05de\u05d9\u05dd \u05e4\u05e8\u05d4 \u05d0\u05d3\u05d5\u05de\u05d4 \u2014 \u05d6\u05e8\u05d9\u05e7\u05d4 \u05d1\u05d9\u05d5\u05dd \u05d2' \u05d5\u05d1\u05d9\u05d5\u05dd \u05d6'. \u05dc\u05dc\u05d0 \u05d6\u05d0\u05ea, \u05d8\u05de\u05d0 \u05dc\u05e2\u05d5\u05dc\u05dd. \u05d4\u05d9\u05d5\u05dd \u05db\u05d5\u05dc\u05e0\u05d5 \u05d1\u05d8\u05d5\u05de\u05d0\u05ea \u05de\u05d9\u05ea."
    ),
    # 12 cloud87 — mikveh
    (
        "\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05d4\u05de\u05d9\u05e7\u05d5\u05d4 \u2014 \u05d1\u05e8\u05d9\u05db\u05ea \u05e9\u05d3\u05e8\u05d5\u05ea \u05db\u05dc \u05db\u05da \u05de\u05d3\u05d5\u05d9\u05e7\u05d5\u05ea \u05e9\u05d4\u05e8\u05d1\u05e0\u05d9\u05dd \u05e6\u05e8\u05d9\u05db\u05d9\u05dd \u05dc\u05d4\u05db\u05d9\u05e8 \u05d1\u05d0\u05d9\u05e0\u05e7\u05e4! \U0001f4a7 "
        "\u05de\u05d9\u05e7\u05d5\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05d1\u05e8\u05d9\u05db\u05d4. \u05d4\u05d4\u05dc\u05db\u05d4 \u05d3\u05d5\u05e8\u05e9\u05ea \u05e0\u05e4\u05d7 \u05de\u05d9\u05e0\u05d9\u05de\u05dc\u05d9 \u05e9\u05dc \u05d0\u05e8\u05d1\u05e2\u05d9\u05dd \u05e9\u05e2\u05d9\u05dd (\u05db-750 \u05dc\u05d9\u05d8\u05e8), \u05de\u05d9\u05dd \u05e9\u05dc\u05d0 \u05e0\u05d8\u05dc\u05d5 \u05de\u05d4\u05d1\u05d0\u05d4 \u2014 \u05de\u05d9\u05dd \u05de\u05d4\u05e9\u05de\u05d9\u05d9\u05dd \u05d0\u05d5 \u05de\u05de\u05e7\u05d5\u05e8 \u05d4\u05dc\u05db\u05d4 \u05de\u05d5\u05ea\u05d0, \u05d5\u05d8\u05d1\u05d9\u05dc\u05d4 \u05de\u05dc\u05d0\u05d4 \u05dc\u05dc\u05d0 \u05db\u05dc \u05d3\u05d1\u05e8 \u05d1\u05d9\u05df \u05d4\u05d2\u05d5\u05e3 \u05dc\u05de\u05d9\u05dd. "
        "\u05e0\u05e9\u05d9\u05dd \u05d0\u05d7\u05e8\u05d9 \u05d4\u05d5\u05e1\u05d8, \u05d2\u05d9\u05d9\u05e8\u05d9\u05dd, \u05d5\u05d2\u05dd \u05d2\u05d1\u05e8\u05d9\u05dd \u05dc\u05e7\u05d3\u05d5\u05e9\u05d4 \u05e0\u05d5\u05e1\u05e4\u05ea. \u05d2\u05dd \u05db\u05dc\u05d9 \u05e7\u05d3\u05e9\u05d9\u05dd \u05de\u05d7\u05d5\u05d5\u05d9 \u05dc\u05d0-\u05d9\u05d4\u05d5\u05d3\u05d9\u05dd \u05de\u05d8\u05d1\u05dc\u05d9\u05dd. "
        f"\u05d1\u05e7\u05d1\u05d9\u05e2\u05ea \u05e7\u05d4\u05d9\u05dc\u05d4 \u05d7\u05d3\u05e9\u05d4 \u05d1\u05d5\u05e0\u05d9\u05dd \u05de\u05d9\u05e7\u05d5\u05d4 \u05dc\u05e4\u05e0\u05d9 \u05d1\u05d9\u05ea \u05d4\u05db\u05e0\u05e1\u05ea \u2014 \u05db\u05d9 \u05d6\u05d4 \u05de\u05d0\u05e4\u05e9\u05e8 \u05dc\u05d1\u05e0\u05d6\u05d5\u05d2 \u05d0\u05d9\u05e9\u05d9 \u05dc\u05d7\u05d9\u05d9\u05dd \u05d9\u05d7\u05d3. \u05dc\u05de\u05d3\u05d5 \u05e2\u05d5\u05d3!"
    ),
    # 13 cloud88 — me'ilah
    (
        "\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05de\u05e2\u05d9\u05dc\u05d4 \u2014 \u05e9\u05d9\u05de\u05d5\u05e9 \u05dc\u05d0 \u05db\u05d3\u05d9 \u05d1\u05e7\u05d3\u05e9 \u05d4\u05de\u05e7\u05d3\u05e9 \u2014 \u05d5\u05dc\u05de\u05d4 \u05d6\u05d4 \u05db\u05dc \u05db\u05da \u05e8\u05e6\u05d9\u05e0\u05d9 \u05d1\u05d4\u05dc\u05db\u05d4! \u26a0\ufe0f "
        "\u05db\u05e9\u05de\u05e9\u05d4\u05d5 \u05de\u05d5\u05e7\u05d3\u05e9 \u05dc\u05d4', \u05d0\u05e1\u05d5\u05e8 \u05dc\u05d4\u05e9\u05ea\u05de\u05e9 \u05d1\u05d5 \u05dc\u05d0\u05d9\u05e9\u05d9. \u05de\u05e2\u05d9\u05dc\u05d4 \u05d4\u05d9\u05d0 \u05db\u05e9\u05de\u05e8\u05d5\u05d5\u05d9\u05d7\u05d9\u05dd \u05d1\u05e8\u05db\u05ea \u05d4\u05e4\u05e0\u05d9\u05dd, \u05de\u05e9\u05ea\u05de\u05e9\u05d9\u05dd \u05d1\u05d1\u05d4\u05de\u05ea \u05de\u05d5\u05e7\u05d3\u05e9\u05ea \u05d0\u05d5 \u05e9\u05d5\u05d0\u05d1\u05d9\u05dd \u05e9\u05de\u05df \u05d4\u05de\u05e7\u05d3\u05e9. "
        "\u05d4\u05e2\u05d5\u05e0\u05e9: \u05d4\u05d7\u05d6\u05e8\u05ea \u05d4\u05e9\u05d5\u05d5\u05d9 \u05d5\u05e2\u05d5\u05d3 \u05d7\u05de\u05d9\u05e9\u05d4 \u05d0\u05d7\u05ea, \u05d5\u05d4\u05d1\u05d0\u05ea \u05e7\u05d5\u05e8\u05d1\u05df \u05d0\u05e9\u05dd. \u05d4\u05e2\u05d1\u05d9\u05e8\u05d4 \u05e0\u05db\u05e0\u05e1\u05ea \u05dc\u05ea\u05d5\u05e7\u05e3 \u05e8\u05e7 \u05db\u05e9\u05de\u05e8\u05d5\u05d5\u05d9\u05d7\u05d9\u05dd \u05d1\u05d0\u05de\u05ea. \u05dc\u05de\u05d3\u05d5 \u05e2\u05d5\u05d3!"
    ),
    # 14 cloud89 — Korban Pesach
    (
        "\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05d0\u05d9\u05e8\u05d5\u05e2 \u05d4\u05e2\u05d5\u05dc\u05dd \u05d4\u05e8\u05d0\u05e9\u05d5\u05df \u05e2\u05dd \u05d0\u05d9\u05e9\u05d5\u05e8 \u05d4\u05d2\u05e2\u05d4 \u2014 \u05e7\u05d5\u05e8\u05d1\u05df \u05d4\u05e4\u05e1\u05d7! \U0001f411 "
        "\u05dc\u05d0 \u05d4\u05d9\u05d4 \u05e8\u05e7 \u05de\u05e6\u05d5\u05d5\u05d4 \u2014 \u05d6\u05d4 \u05d4\u05d9\u05d4 \u05e0\u05e1 \u05dc\u05d5\u05d2\u05d9\u05e1\u05d8\u05d9. \u05db\u05dc \u05d0\u05d3\u05dd \u05d4\u05d9\u05d4 \u05e6\u05e8\u05d9\u05da \u05dc\u05d4\u05d9\u05e8\u05e9\u05dd \u05dc\u05d7\u05d1\u05d5\u05e8\u05d4 \u05dc\u05e4\u05e0\u05d9 \u05d4\u05e9\u05e7\u05d9\u05e2\u05d4. \u05dc\u05dc\u05d0 \u05e8\u05d9\u05e9\u05d5\u05dd \u2014 \u05dc\u05d0 \u05d0\u05d5\u05db\u05dc\u05d9\u05dd! \U0001f4dd "
        "\u05d1\u05e6\u05d4\u05e8\u05d9\u05d9\u05dd \u05e9\u05dc \u05d9\"\u05d3 \u05d1\u05e0\u05d9\u05e1\u05df \u05db\u05d5\u05dc \u05d4\u05e2\u05dd \u05d4\u05ea\u05e7\u05d1\u05dc \u05d1\u05de\u05e7\u05d3\u05e9. \u05d4\u05db\u05d4\u05e0\u05d9\u05dd \u05d7\u05dc\u05e7\u05d5 \u05dc\u05e9\u05dc\u05d5\u05e9\u05ea \u05de\u05e9\u05de\u05e8\u05d5\u05ea \u05e2\u05e0\u05e7 \u05d5\u05d4\u05d3\u05dd \u05e2\u05d1\u05e8 \u05de\u05d9\u05d3 \u05d1\u05d9\u05d3 \u05d1\u05e2\u05d1\u05d5\u05d3\u05ea \u05de\u05e9\u05d0 \u05e9\u05dc \u05de\u05e9\u05d0 \u05d4\u05e7\u05d3\u05e9. "
        "\u05d0\u05e1\u05d5\u05e8 \u05dc\u05e9\u05d1\u05d5\u05e8 \u05e2\u05e6\u05dd \u05d5\u05dc\u05d0 \u05dc\u05e9\u05d1\u05d5\u05e8 \u05e2\u05e6\u05dd. \u05d4\u05dc\u05d7\u05e5 \u05d4\u05d9\u05ea\u05d4 \u05dc\u05e1\u05d9\u05d9\u05dd \u05dc\u05e4\u05e0\u05d9 \u05d7\u05e6\u05d5\u05ea \u05d1\u05e2\u05d5\u05d3 \u05e9\u05db\u05d5\u05dc \u05d4\u05e2\u05d9\u05e8 \u05e9\u05e8 \u05d4\u05dc\u05dc. \u05ea\u05d6 \u05db\u05d9 \u05e0\u05d6\u05db\u05d4 \u05dc\u05d7\u05d5\u05d5\u05ea \u05d0\u05ea \u05d6\u05d4 \u05d1\u05d9\u05de\u05d9\u05e0\u05d5! \u05dc\u05de\u05d3\u05d5 \u05e2\u05d5\u05d3! \U0001f389\U0001f377"
    ),
    # 15 cloud90 — machatzit hashekel
    (
        "\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05de\u05d7\u05e6\u05d9\u05ea \u05d4\u05e9\u05e7\u05dc \u2014 \u05d5\u05e2\u05dc \u05d4\u05e7\u05e9\u05e8 \u05d4\u05de\u05e8\u05ea\u05e7 \u05dc\u05e4\u05d5\u05e8\u05d9\u05dd! \U0001fa99 "
        "\u05db\u05dc \u05e9\u05e0\u05d4 \u05de\u05e8\u05d0\u05e9 \u05d7\u05d5\u05d3\u05e9 \u05d0\u05d3\u05e8 \u05de\u05d6\u05db\u05d9\u05e8\u05d9\u05dd: \u05d6\u05de\u05df \u05dc\u05ea\u05ea \u05de\u05d7\u05e6\u05d9\u05ea \u05e9\u05e7\u05dc! \u05d2\u05d3\u05d5\u05dc \u05d0\u05d5 \u05e2\u05e0\u05d9 \u2014 \u05d0\u05d5\u05ea\u05d4 \u05db\u05de\u05d5\u05ea. \u05dc\u05d0 \u05e9\u05e7\u05dc \u05e9\u05dc\u05dd, \u05db\u05d9 \u05d0\u05d9\u05df \u05ea\u05e8\u05d5\u05de\u05ea \u05de\u05dc\u05d0\u05d4 \u05dc\u05dc\u05d0 \u05db\u05d5\u05dc\u05dd. "
        "\u05d4\u05e7\u05e9\u05e8 \u05dc\u05e4\u05d5\u05e8\u05d9\u05dd: \u05d4\u05de\u05e8\u05d9\u05e5 \u05d0\u05d5\u05de\u05e8 \u05e9\u05e9\u05e7\u05dc\u05d9 \u05d9\u05e9\u05e8\u05d0\u05dc \u05e7\u05d3\u05de\u05d5 \u05dc\u05e9\u05e7\u05dc\u05d9 \u05d4\u05de\u05df. \u05dc\u05db\u05df \u05e0\u05d4\u05d2 \u05dc\u05ea\u05ea \u05e9\u05dc\u05d5\u05e9 \u05de\u05d7\u05e6\u05d9\u05d5\u05ea \u05e9\u05e7\u05dc \u05dc\u05e4\u05e0\u05d9 \u05e4\u05d5\u05e8\u05d9\u05dd."
    ),
    # 16 cloud91 — korban oleh v'yored
    (
        "\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05de\u05e2\u05e8\u05db\u05ea \u05d4\u05e1\u05d5\u05dc\u05de\u05d4 \u05d4\u05e0\u05d9\u05d3\u05d7\u05ea \u05e9\u05dc\u05d0 \u05d4\u05e9\u05d0\u05d9\u05e8\u05d4 \u05d0\u05e3 \u05d0\u05d7\u05d3 \u05de\u05d7\u05d5\u05e5 \u05dc\u05d4\u05ea\u05d7\u05dc \u05de\u05d7\u05d3\u05e9! \U0001f54a\ufe0f "
        "\u05e7\u05d5\u05e8\u05d1\u05df \u05e2\u05d5\u05dc\u05d4 \u05d5\u05d9\u05d5\u05e8\u05d3 \u2014 \u05e2\u05d5\u05d3 \u05d3\u05d5\u05d2\u05de\u05d4 \u05e9\u05d4' \u05d3\u05d0\u05d2 \u05dc\u05db\u05dc \u05d9\u05d4\u05d5\u05d3\u05d9. \u05e2\u05e9\u05d9\u05e8 \u2014 \u05d1\u05d4\u05de\u05d4; \u05e7\u05e9\u05d4 \u2014 \u05e6\u05d9\u05e4\u05d5\u05e8\u05d9\u05dd \u05d0\u05d5 \u05d0\u05e4\u05d9\u05dc\u05d5 \u05e7\u05de\u05d7 \u05d3\u05e7\u05d4! \U0001f33e "
        "\u05dc\u05d0 \u05de\u05d3\u05d3 \u05d4\u05de\u05ea\u05e0\u05d4 \u05d0\u05dc\u05d0 \u05d4\u05dc\u05d1. \u05d4\u05de\u05e9\u05d9\u05de\u05d4 \u05e9\u05dc\u05db\u05dd: \u05d7\u05e9\u05d1\u05d5 \u05e2\u05dc \u05db\u05d9 \u05d4' \u05e8\u05d5\u05e6\u05d4 \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05e2\u05dd \u05db\u05dc \u05d0\u05d7\u05d3 \u05de\u05ea\u05d5\u05da \u05d4\u05dc\u05d1, \u05dc\u05d0 \u05e8\u05e7 \u05de\u05d4\u05db\u05d9\u05e1."
    ),
    # 17 cloud92 — simchat yom tov
    (
        "\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05d4\u05e6\u05d5 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9 \u05dc\u05d7\u05d2\u05d5\u05d2 \u05d0\u05ea \u05d4\u05e8\u05d2\u05e2 \u05d4\u05d8\u05d5\u05d1 \u05d1\u05d9\u05d5\u05ea\u05e8 \u05de\u05d7\u05d9\u05d9\u05db\u05d9\u05dd! \U0001f389 "
        "\u05d4\u05ea\u05d5\u05e8\u05d4 \u05dc\u05d0 \u05e8\u05e7 \u05de\u05de\u05dc\u05d9\u05e6\u05d4 \u05dc\u05e9\u05de\u05d5\u05d7 \u05d1\u05d7\u05d2 \u2014 \u05d4\u05d9\u05d0 \u05de\u05e6\u05d5\u05d5\u05d4 \u05d1\u05e9\u05de\u05d7\u05ea \u05d9\u05d5\u05dd \u05d8\u05d5\u05d1. \u05d1\u05e9\u05dc\u05d5\u05e9\u05ea \u05d4\u05e8\u05d2\u05e2\u05d9\u05dd \u05d4\u05d2\u05d3\u05d5\u05dc\u05d9\u05dd: \u05e4\u05e1\u05d7, \u05e9\u05d1\u05d5\u05e2\u05d5\u05ea \u05d5\u05d9\u05d9\u05df \u05d4\u05dd \u05db\u05de\u05e2\u05d8 \u05de\u05e7\u05d5\u05d3\u05e9. \U0001f377\U0001f969 "
        "\u05dc\u05d0\u05e0\u05e9\u05d9\u05dd \u2014 \u05d1\u05e9\u05e8 \u05d5\u05d9\u05d9\u05df; \u05dc\u05e0\u05e9\u05d9\u05dd \u2014 \u05d1\u05d2\u05d3 \u05d0\u05d5 \u05ea\u05db\u05e9\u05d9\u05d8\u05d9\u05dd \u05d7\u05d3\u05e9\u05d9\u05dd; \u05dc\u05d9\u05dc\u05d3\u05d9\u05dd \u2014 \u05de\u05ea\u05e7\u05d5\u05ea. "
        "\u05d0\u05d1\u05dc \u05d4\u05d7\u05db\u05de\u05d9\u05dd \u05de\u05d6\u05d4\u05d9\u05e8\u05d9\u05dd: \u05e8\u05e7 \u05e2\u05dd \u05d4\u05de\u05e9\u05e4\u05d7\u05d4 \u05d6\u05d4 \u05e8\u05e7 \u05e9\u05de\u05d7\u05ea \u05d1\u05d8\u05df, \u05dc\u05d0 \u05e9\u05d9\u05de\u05d7\u05ea \u05d9\u05d5\u05dd \u05d8\u05d5\u05d1. \u05e6\u05e8\u05d9\u05da \u05db\u05d9\u05e1 \u05dc\u05e2\u05e0\u05d9\u05d9\u05dd \u05d5\u05dc\u05d1\u05d3\u05d5\u05d3\u05d9\u05dd. \u05dc\u05de\u05d3\u05d5 \u05e2\u05d5\u05d3!"
    ),
    # 18 cloud93 — shemittah
    (
        "\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05e9\u05de\u05d9\u05d8\u05d4 \u2014 \u05d4\u05e9\u05e0\u05d4 \u05e9\u05d4\u05d0\u05d3\u05de\u05d4 \u05e0\u05d7\u05d4 \u05d1\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc! \U0001f33e "
        "\u05db\u05dc \u05e9\u05e9\u05d9 \u05e9\u05e0\u05d9\u05dd \u05d4\u05d0\u05d3\u05de\u05d4 \u05e0\u05d7\u05d4 \u2014 \u05dc\u05dc\u05d0 \u05d7\u05e8\u05d9\u05e9\u05d4 \u05de\u05e1\u05d7\u05e8\u05d9\u05ea. \u05e4\u05d9\u05e8\u05d5\u05ea \u05e2\u05dd \u05e7\u05d3\u05d5\u05e9\u05ea \u05e9\u05d1\u05d9\u05e2\u05d9\u05ea \u05dc\u05d0 \u05e0\u05de\u05db\u05e8\u05d5\u05ea \u05db\u05e8\u05d2\u05d9\u05dc. "
        "\u05d4\u05d9\u05d5\u05dd \u05d1\u05d9\u05e9\u05e8\u05d0\u05dc \u05d4\u05d8\u05d9\u05e4\u05d5\u05dc \u05db\u05d5\u05dc\u05dc \u05d4\u05ea\u05e8 \u05de\u05d7\u05d9\u05e8\u05d4 \u05d5\u05d0\u05d5\u05e6\u05e8 \u05d1\u05d9\u05ea \u05d3\u05d9\u05df. \u05dc\u05d0 \u05dc\u05d6\u05e8\u05e7 \u05d0\u05d5 \u05dc\u05d4\u05e9\u05d7\u05d9\u05ea \u05de\u05d6\u05d5\u05df \u05de\u05ea\u05db\u05d5\u05d5\u05df \u05d1\u05de\u05d5\u05d3\u05e2. \u05dc\u05de\u05d3\u05d5 \u05e2\u05d5\u05d3!"
    ),
    # 19 cloud94 — terumah/maaser
    (
        "\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05de\u05e2\u05e8\u05db\u05ea \u05d4\u05de\u05e2\u05e9\u05e8\u05d5\u05ea \u05d1\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc! \U0001f9fa "
        "\u05dc\u05e4\u05e0\u05d9 \u05db\u05dc \u05e0\u05e9\u05d9\u05db\u05d4 \u05de\u05e4\u05e8\u05d9\u05d3\u05d9\u05dd \u05ea\u05e8\u05d5\u05de\u05d4 \u05dc\u05db\u05d4\u05e0\u05d9\u05dd, \u05de\u05e2\u05e9\u05e8 \u05e8\u05d0\u05e9\u05d5\u05df \u05dc\u05dc\u05d5\u05d9\u05d9\u05dd, \u05d5\u05de\u05e2\u05e9\u05e8 \u05e9\u05e0\u05d9 \u05d0\u05d5 \u05de\u05e2\u05e9\u05e8 \u05e2\u05e0\u05d9 \u05dc\u05e2\u05e0\u05d9\u05d9\u05dd \u05dc\u05e4\u05d9 \u05e9\u05e0\u05ea \u05d4\u05e9\u05de\u05d9\u05d8\u05d4. "
        "\u05d6\u05d5 \u05de\u05e1 \u05d2\u05d1\u05d5\u05d4 \u05e9\u05de\u05d6\u05db\u05d9\u05e8 \u05dc\u05e0\u05d5 \u05e9\u05d4\u05d0\u05d3\u05de\u05d4 \u05e9\u05d9\u05d9\u05db\u05ea \u05dc\u05d4'. \u05dc\u05de\u05d3\u05d5 \u05e2\u05d5\u05d3!"
    ),
    # 20 cloud95 — bikkurim
    (
        "\u05d4\u05db\u05d9\u05e0\u05d5 \u05dc\u05de\u05e6\u05e2\u05d3 \u05d4\u05d1\u05db\u05d5\u05e8\u05d9\u05dd \u05d4\u05e1\u05d5\u05e4\u05d9! \U0001f347 "
        "\u05d1\u05d9\u05db\u05d5\u05e8\u05d9\u05dd \u2014 \u05d1\u05db\u05d5\u05e8\u05ea \u05d4\u05e4\u05e8\u05d9\u05d5\u05ea \u05d4\u05e8\u05d0\u05e9\u05d5\u05e0\u05d5\u05ea \u05de\u05e9\u05d1\u05e2 \u05d4\u05de\u05d9\u05e0\u05d9\u05dd. \u05d4\u05de\u05e1\u05e2 \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05d4\u05d9\u05d4 \u05d7\u05d2 \u05d0\u05e8\u05e6\u05d9 \u05e2\u05dd \u05de\u05d5\u05d6\u05d9\u05e7\u05ea \u05d4\u05dc\u05d5\u05d9\u05d9\u05dd. "
        "\u05d4\u05d0\u05d9\u05db\u05e8 \u05de\u05e1\u05e4\u05e8 \u05d0\u05ea \u05d4\u05d4\u05d9\u05e1\u05d8\u05d5\u05e8\u05d9\u05d4 \u05de\u05d4\u05d9\u05e6\u05d9\u05d0\u05ea \u05de\u05d9\u05e6\u05e8\u05d9\u05dd \u05e2\u05d3 \u05dc\u05e2\u05de\u05d3 \u05d1\u05d0\u05d3\u05de\u05ea\u05db\u05dd. \u05ea\u05e6\u05e4\u05d5 \u05dc\u05d7\u05d2 \u05e9\u05d5\u05d1 \u05d1\u05de\u05e7\u05d3\u05e9 \u05d4\u05e9\u05dc\u05d9\u05e9\u05d9! \U0001f389\U0001f34e"
    ),
    # 21 cloud96 — halvayat hameit
    (
        f"\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05d4\u05dc\u05d5\u05d5\u05d0\u05ea \u05d4\u05de\u05d9\u05ea \u2014 \u05d7\u05e1\u05d3 \u05e9\u05dc \u05d0\u05de\u05ea \u05d0\u05de\u05d9\u05ea\u05d9! \U0001f4dc "
        f"{RAMBAM} \u05de\u05e1\u05d1\u05d9\u05e8 \u05e9\u05d6\u05d5 \u05de\u05e6\u05d5\u05d5\u05ea \u05ea\u05d5\u05e8\u05d4 \u05de\u05dc\u05d0\u05d4 \u05de\u05d0\u05d4\u05d1\u05ea \u05dc\u05e8\u05e2\u05da \u05db\u05de\u05d5\u05da. "
        "\u05d2\u05dd \u05dc\u05dc\u05db\u05ea \u05db\u05de\u05d4 \u05e6\u05e2\u05d3\u05d9\u05dd \u05e2\u05dd \u05d4\u05de\u05d9\u05ea \u05d4\u05d5\u05d0 \u05de\u05e6\u05d5\u05d5\u05d4 \u05e2\u05e6\u05d5\u05de\u05d4 \u05d2\u05d3\u05d5\u05dc\u05d4 \u05dc\u05e0\u05e9\u05de\u05d4 \u05d4\u05e0\u05e4\u05e1\u05d3\u05ea. \u05dc\u05de\u05d3\u05d5 \u05e2\u05d5\u05d3!"
    ),
    # 22 cloud97 — chukot ha'akum
    (
        "\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05d0\u05d9\u05e1\u05d5\u05e8 \u05d7\u05d5\u05e7\u05d5\u05ea \u05d4\u05d0\u05d5\u05de\u05d5\u05ea \u2014 \u05dc\u05d0 \u05dc\u05dc\u05db\u05ea \u05d1\u05de\u05e0\u05d4\u05d2\u05d9 \u05d4\u05d2\u05d5\u05d9\u05d9\u05dd! \U0001f54a\ufe0f "
        f"{RAMBAM} \u05d5{SHU} \u05e7\u05d5\u05d1\u05e2\u05d9\u05dd \u05d0\u05ea \u05d4\u05d0\u05d9\u05e1\u05d5\u05e8 \u05dc\u05d4\u05e2\u05ea\u05d9\u05e7 \u05dc\u05de\u05e0\u05d4\u05d2\u05d9 \u05d3\u05ea\u05d9 \u05d0\u05d5 \u05e2\u05d1\u05d5\u05d3\u05d4 \u05d2\u05d5\u05d9\u05d9\u05ea. "
        "\u05de\u05d5\u05ea\u05e8: \u05d3\u05d1\u05e8\u05d9\u05dd \u05e9\u05d4\u05ea\u05e4\u05e9\u05d8\u05d5 \u05dc\u05de\u05d8\u05e8\u05d5\u05ea \u05e2\u05e9\u05d9\u05ea \u05d1\u05dc\u05d1\u05d3. \u05d4\u05d0\u05d9\u05e1\u05d5\u05e8 \u05e0\u05d5\u05d2\u05e2 \u05dc\u05de\u05e0\u05d4\u05d2\u05d9\u05dd \u05d3\u05ea\u05d9\u05d9\u05dd \u05d0\u05d5 \u05e2\u05d1\u05d5\u05d3\u05d4 \u05d2\u05d5\u05d9\u05d9\u05ea \u05d1\u05dc\u05d1\u05d3."
    ),
    # 23 cloud98 — Rambam mashiach
    (
        f"\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05ea\u05e9\u05d5\u05d1\u05ea {RAMBAM} \u05e2\u05dc \u05d9\u05de\u05d5\u05ea \u05d4\u05de\u05e9\u05d9\u05d7 \u2014 \u05d0\u05d5\u05dc\u05d9 \u05d4\u05d9 \u05d2\u05e9\u05de\u05d9\u05ea \u05d9\u05d5\u05ea\u05e8 \u05de\u05e9\u05e6\u05e4\u05ea! \U0001f30d "
        f"{RAMBAM} \u05de\u05d1\u05d4\u05d9\u05e8 \u05e9\u05d9\u05de\u05d5\u05ea \u05d4\u05de\u05e9\u05d9\u05d7 \u05ea\u05d4\u05d9\u05d4 \u05d8\u05d1\u05e2\u05d9\u05ea, \u05dc\u05d0 \u05e0\u05e1\u05d9\u05ea \u2014 \u05d4\u05e9\u05de\u05e9 \u05d9\u05d6\u05e8\u05d7 \u05d5\u05d9\u05e9\u05e7\u05e2 \u05db\u05e8\u05d2\u05d9\u05dc. "
        "\u05d4\u05d4\u05d1\u05d3\u05dc \u05d4\u05d2\u05d3\u05d5\u05dc: \u05d9\u05e9\u05e8\u05d0\u05dc \u05d7\u05e4\u05e9\u05d9 \u05de\u05e2\u05d5\u05df \u05d5\u05d9\u05d5\u05db\u05dc \u05dc\u05dc\u05de\u05d5\u05d3 \u05ea\u05d5\u05e8\u05d4 \u05dc\u05dc\u05d0 \u05d4\u05e1\u05d7\u05d5\u05ea. \u05d9\u05e9 \u05d7\u05db\u05de\u05d9\u05dd \u05e9\u05d7\u05d5\u05dc\u05e7\u05d9\u05dd \u2014 \u05de\u05d4 \u05dc\u05d3\u05e2\u05ea\u05db\u05dd?"
    ),
    # 24 cloud99 — lashon hara exceptions
    (
        f"\u05dc\u05de\u05d3\u05d5 \u05de\u05ea\u05d9 \u05de\u05d5\u05ea\u05e8 \u05dc\u05d3\u05d1\u05e8 \u05e8\u05e2 \u05d0\u05d3\u05dd \u2014 \u05dc\u05e9\u05d5\u05df \u05d4\u05e8\u05e2 \u05d9\u05e9 \u05d7\u05e8\u05d9\u05d2\u05d9\u05dd! \U0001f444 "
        f"{CHOFETZ} \u05e7\u05d5\u05d1\u05e2 \u05e9\u05d1\u05e2 \u05ea\u05e0\u05d0\u05d9\u05dd \u05d7\u05d9\u05d9\u05d1\u05d9\u05dd \u05dc\u05db\u05dc \u05d4\u05ea\u05e0\u05d0\u05d9\u05dd: \u05d0\u05de\u05ea, \u05e6\u05d5\u05e8\u05da, \u05e0\u05d9\u05e1\u05d9\u05d5\u05df \u05dc\u05d3\u05d1\u05e8 \u05e2\u05dd \u05d4\u05e4\u05d5\u05d2\u05e2, \u05e4\u05e8\u05d5\u05e4\u05d5\u05e8\u05e6\u05d9\u05d4, \u05db\u05d5\u05d5\u05e0\u05d4 \u05d8\u05d4\u05d5\u05e8\u05d4, \u05d4\u05e4\u05d7\u05ea\u05ea \u05e0\u05d6\u05e7 \u05d5\u05d0\u05d9\u05df \u05d3\u05e8\u05da \u05d0\u05d7\u05e8\u05ea. "
        "\u05d4\u05d3\u05d5\u05d2\u05de\u05d4 \u05d4\u05de\u05d5\u05ea\u05e8\u05ea: \u05dc\u05d4\u05d6\u05d4\u05d9\u05e8 \u05e2\u05dc \u05e0\u05d5\u05db\u05dc \u05d4\u05d5\u05e0\u05d0\u05ea \u05e9\u05d5\u05d8\u05d4. \u05dc\u05de\u05d3\u05d5 \u05e2\u05d5\u05d3!"
    ),
    # 25 cloud100 — receiving lashon hara
    (
        f"\u05dc\u05de\u05d3\u05d5 \u05e2\u05dc \u05d0\u05d9\u05e1\u05d5\u05e8 \u05dc\u05e7\u05d1\u05dc \u05dc\u05e9\u05d5\u05df \u05d4\u05e8\u05e2 \u2014 \u05d7\u05de\u05d5\u05e8 \u05db\u05de\u05d3\u05d1\u05e8 \u05d5\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d0\u05e4\u05d9\u05dc\u05d5 \u05e7\u05e9\u05d4 \u05d9\u05d5\u05ea\u05e8 \u05dc\u05d4\u05d9\u05de\u05e0\u05e2! \U0001f910 "
        f"{CHOFETZ} \u05e7\u05d5\u05d1\u05e2: \u05d0\u05e1\u05d5\u05e8 \u05dc\u05d4\u05d0\u05de\u05d9\u05df \u05d5\u05dc\u05d4\u05e0\u05d5\u05ea \u05d1\u05e9\u05d9\u05de\u05d5\u05d7 \u05d0\u05ea \u05d4\u05d3\u05d1\u05e8\u05d9\u05dd. "
        f"{TALMUD} \u05d0\u05d5\u05de\u05e8 \u05e9\u05d4\u05e9\u05d5\u05de\u05e2 \u05d2\u05e8\u05d5\u05e2 \u05de\u05d4\u05de\u05d3\u05d1\u05e8 \u2014 \u05db\u05d9 \u05d4\u05e0\u05d6\u05e7 \u05db\u05d1\u05e8 \u05d4\u05d6\u05d9\u05e7 \u05d1\u05dc\u05d1\u05d5 \u05d5\u05d4\u05e0\u05d6\u05e7 \u05db\u05d1\u05e8 \u05e7\u05d9\u05d1\u05dc \u05d0\u05ea \u05d4\u05de\u05d9\u05d3\u05e2. "
        "\u05d0\u05dd \u05e0\u05ea\u05e7\u05e2\u05d9\u05dd \u2014 \u05e0\u05e1\u05d5 \u05dc\u05d4\u05e1\u05d9\u05d8 \u05d0\u05d5 \u05dc\u05e6\u05d0\u05ea; \u05d0\u05dd \u05ea\u05e7\u05d5\u05e2\u05d9\u05dd \u2014 \u05e9\u05d5\u05de\u05e2\u05d9\u05dd \u05d1\u05dc\u05d0 \u05de\u05d0\u05de\u05d9\u05e0\u05d9\u05dd. \u05de\u05e7\u05d5\u05e8: \u05d7\u05e4\u05e5 \u05d7\u05d9\u05dd, \u05d4\u05dc\u05db\u05d5\u05ea \u05e8\u05db\u05d9\u05dc\u05d5\u05ea; \u05ea\u05dc\u05de\u05d5\u05d3, \u05e0\u05d3\u05d4 \u05e1\"\u05d0."
    ),
]
